  1→/**
  2→ * Global Session Notifications
  3→ *
  4→ * Sends OS-level notifications when the app is in the background.
  5→ *
  6→ * Notification triggers:
  7→ * - Agent finished working (working → idle)                → Glass sound
  8→ * - Agent error (→ error with error_category)              → Basso sound
  9→ * - Agent needs input (→ needs_response)                   → Ping sound
 10→ * - Plan ready for review (→ needs_plan_response)          → Ping sound
 11→ * - Setup failed/completed                                 → Basso/Glass sound
 12→ *
 13→ * All transitions are detected by observing the workspace React Query cache,
 14→ * which is kept fresh by the WS subscription. No IPC event listeners needed.
 15→ *
 16→ * When the app is in the foreground, notifications are suppressed —
 17→ * Sonner toasts handle in-app feedback.
 18→ */
 19→
 20→import { useEffect, useRef } from "react";
 21→import { useQueryClient } from "@tanstack/react-query";
 22→import { match } from "ts-pattern";
 23→import { capabilities } from "@/platform/capabilities";
 24→import { sendNotification } from "@/platform/notifications";
 25→import { isWindowFocused } from "@/shared/hooks/useWindowFocus";
 26→import { track } from "@/platform/analytics";
 27→import { unreadActions } from "@/features/session/store/unreadStore";
 28→import { useWorkspaceStore } from "@/features/workspace/store";
 29→import { workspaceLayoutActions } from "@/features/workspace/store/workspaceLayoutStore";
 30→import { show as showWindow } from "@/platform/native/window";
 31→import type { SessionStatus } from "@shared/types/session";
 32→import type { RepoGroup, SetupStatus, Workspace } from "@shared/types/workspace";
 33→
 34→/**
 35→ * Batches multiple notifications within a short window into a single one.
 36→ * Prevents notification spam when multiple agents finish simultaneously.
 37→ */
 38→const BATCH_WINDOW_MS = 1500;
 39→
 40→interface FinishedEntry {
 41→  workspaceId: string;
 42→  sessionId: string;
 43→  repoName: string;
 44→  label: string;
 45→}
 46→
 47→function formatBody(repoName: string, ws: Workspace): string {
 48→  const label = ws.title || ws.git_branch || ws.slug;
 49→  return `${repoName} · ${label}`;
 50→}
 51→
 52→function navigateToWorkspace(workspaceId: string, sessionId: string): void {
 53→  showWindow();
 54→  useWorkspaceStore.getState().selectWorkspace(workspaceId);
 55→  const layout = workspaceLayoutActions.getLayout(workspaceId);
 56→  if (layout.activeChatTabSessionId !== sessionId) {
 57→    const sessionIds = layout.chatTabSessionIds.includes(sessionId)
 58→      ? layout.chatTabSessionIds
 59→      : [...layout.chatTabSessionIds, sessionId];
 60→    workspaceLayoutActions.setChatTabState(workspaceId, sessionIds, sessionId);
 61→  }
 62→}
 63→
 64→/**
 65→ * Check if the user is currently viewing a specific session.
 66→ * True when the workspace is selected AND the active chat tab matches the session.
 67→ */
 68→function checkIsViewingSession(workspaceId: string, sessionId: string): boolean {
 69→  const selectedWorkspaceId = useWorkspaceStore.getState().selectedWorkspaceId;
 70→  if (selectedWorkspaceId !== workspaceId) return false;
 71→
 72→  const layout = workspaceLayoutActions.getLayout(workspaceId);
 73→  // If no persisted active tab, the workspace's current_session_id is shown
 74→  return layout.activeChatTabSessionId === sessionId || !layout.activeChatTabSessionId;
 75→}
 76→
 77→export function useGlobalSessionNotifications() {
 78→  const prevStatusMap = useRef(new Map<string, SessionStatus>());
 79→  const prevSetupStatusMap = useRef(new Map<string, SetupStatus>());
 80→  const finishedBatch = useRef<FinishedEntry[]>([]);
 81→  const batchTimerRef = useRef<ReturnType<typeof setTimeout>>();
 82→
 83→  const queryClient = useQueryClient();
 84→
 85→  useEffect(() => {
 86→    const canNotify = capabilities.nativeNotifications;
 87→
 88→    function flushFinishedBatch() {
 89→      const batch = finishedBatch.current;
 90→      finishedBatch.current = [];
 91→      batchTimerRef.current = undefined;
 92→
 93→      if (batch.length === 0 || isWindowFocused()) return;
 94→
 95→      if (batch.length === 1) {
 96→        const entry = batch[0];
 97→        sendNotification({
 98→          title: "Agent finished",
 99→          body: `${entry.repoName} · ${entry.label}`,
100→          sound: "Glass",
101→          onClick: () => navigateToWorkspace(entry.workspaceId, entry.sessionId),
102→        });
103→      } else {
104→        const repos = [...new Set(batch.map((e) => e.repoName))];
105→        const body =
106→          repos.length === 1
107→            ? `${repos[0]} · ${batch.length} workspaces`
108→            : `${repos[0]} + ${repos.length - 1} more`;
109→        const first = batch[0];
110→        sendNotification({
111→          title: `${batch.length} agents finished`,
112→          body,
113→          sound: "Glass",
114→          onClick: () => navigateToWorkspace(first.workspaceId, first.sessionId),
115→        });
116→      }
117→    }
118→
119→    function queueFinished(entry: FinishedEntry) {
120→      finishedBatch.current.push(entry);
121→      if (!batchTimerRef.current) {
122→        batchTimerRef.current = setTimeout(flushFinishedBatch, BATCH_WINDOW_MS);
123→      }
124→    }
125→
126→    // Detect session + setup transitions from the workspace query cache.
127→    // Only watches current_session_id per workspace. Non-current sessions
128→    // (extra tabs) are handled by ChatArea which tracks workingSessionIds.
129→    const unsubscribe = queryClient.getQueryCache().subscribe((event) => {
130→      if (event.type !== "updated" || !event.query.queryKey[0]) return;
131→
132→      const key = event.query.queryKey;
133→      if (key[0] !== "workspaces" || key[1] !== "by-repo") return;
134→
135→      const groups = event.query.state.data as RepoGroup[] | undefined;
136→      if (!groups) return;
137→
138→      for (const group of groups) {
139→        for (const ws of group.workspaces) {
140→          // --- Session status transitions ---
141→          if (ws.current_session_id && ws.session_status) {
142→            const sessionId = ws.current_session_id;
143→            const status = ws.session_status as SessionStatus;
144→            const prevStatus = prevStatusMap.current.get(sessionId);
145→            prevStatusMap.current.set(sessionId, status);
146→
147→            if (prevStatus && prevStatus !== status) {
148→              // Mark session as unread when transitioning out of "working"
149→              // to any terminal state — but only if user is not currently
150→              // viewing that exact session.
151→              if (
152→                prevStatus === "working" &&
153→                (status === "idle" ||
154→                  status === "error" ||
155→                  status === "needs_response" ||
156→                  status === "needs_plan_response")
157→              ) {
158→                const isViewingSession = checkIsViewingSession(ws.id, sessionId);
159→                if (!isViewingSession) {
160→                  unreadActions.markUnread(sessionId);
161→                }
162→              }
163→
164→              // working → idle = agent finished
165→              if (prevStatus === "working" && status === "idle") {
166→                track("ai_turn_completed", { session_id: sessionId });
167→                if (canNotify && !isWindowFocused()) {
168→                  queueFinished({
169→                    workspaceId: ws.id,
170→                    sessionId,
171→                    repoName: group.repo_name,
172→                    label: ws.title || ws.git_branch || ws.slug,
173→                  });
174→                }
175→              }
176→
177→              // → needs_response = agent needs user input
178→              if (status === "needs_response" && canNotify && !isWindowFocused()) {
179→                sendNotification({
180→                  title: "Agent needs input",
181→                  body: formatBody(group.repo_name, ws),
182→                  sound: "Ping",
183→                  onClick: () => navigateToWorkspace(ws.id, sessionId),
184→                });
185→              }
186→
187→              // → needs_plan_response = plan ready for review
188→              if (status === "needs_plan_response" && canNotify && !isWindowFocused()) {
189→                sendNotification({
190→                  title: "Plan ready for review",
191→                  body: formatBody(group.repo_name, ws),
192→                  sound: "Ping",
193→                  onClick: () => navigateToWorkspace(ws.id, sessionId),
194→                });
195→              }
196→
197→              // → error = agent errored (with category-aware title)
198→              if (status === "error") {
199→                const category = ws.session_error_category ?? undefined;
200→                track("session_error_displayed", {
201→                  session_id: sessionId,
202→                  error_category: category,
203→                });
204→
205→                if (canNotify && !isWindowFocused()) {
206→                  const title = match(category)
207→                    .with("auth", () => "Authentication Error")
208→                    .with("rate_limit", () => "Rate Limited")
209→                    .with("context_limit", () => "Context Limit Reached")
210→                    .with("network", () => "Network Error")
211→                    .with("db_write", () => "Database Error")
212→                    .with("process_exit", () => "Agent Process Crashed")
213→                    .otherwise(() => "Agent Error");
214→                  const context = formatBody(group.repo_name, ws);
215→                  sendNotification({
216→                    title,
217→                    body: ws.session_error_message
218→                      ? `${context} — ${ws.session_error_message}`
219→                      : context,
220→                    sound: "Basso",
221→                    onClick: () => navigateToWorkspace(ws.id, sessionId),
222→                  });
223→                }
224→              }
225→            }
226→          }
227→
228→          // --- Setup status transitions ---
229→          const prevSetup = prevSetupStatusMap.current.get(ws.id);
230→          prevSetupStatusMap.current.set(ws.id, ws.setup_status);
231→
232→          if (!prevSetup) continue;
233→          if (prevSetup === ws.setup_status) continue;
234→
235→          if (
236→            prevSetup === "running" &&
237→            (ws.setup_status === "failed" || ws.setup_status === "completed")
238→          ) {
239→            track("workspace_setup_completed", {
240→              workspace_id: ws.id,
241→              setup_status: ws.setup_status,
242→            });
243→          }
244→
245→          if (
246→            prevSetup === "running" &&
247→            ws.setup_status === "failed" &&
248→            canNotify &&
249→            !isWindowFocused()
250→          ) {
251→            const context = formatBody(group.repo_name, ws);
252→            sendNotification({
253→              title: "Setup failed",
254→              body: ws.error_message ? `${context} — ${ws.error_message}` : context,
255→              sound: "Basso",
256→              onClick: () => {
257→                showWindow();
258→                useWorkspaceStore.getState().selectWorkspace(ws.id);
259→              },
260→            });
261→          }
262→
263→          if (prevSetup === "running" && ws.setup_status === "completed") {
264→            queryClient.invalidateQueries({ queryKey: ["workspaces", "manifest", ws.id] });
265→            if (canNotify && !isWindowFocused()) {
266→              sendNotification({
267→                title: "Setup complete",
268→                body: formatBody(group.repo_name, ws),
269→                sound: "Glass",
270→                onClick: () => {
271→                  showWindow();
272→                  useWorkspaceStore.getState().selectWorkspace(ws.id);
273→                },
274→              });
275→            }
276→          }
277→        }
278→      }
279→    });
280→
281→    return () => {
282→      unsubscribe();
283→      if (batchTimerRef.current) clearTimeout(batchTimerRef.current);
284→    };
285→  }, [queryClient]);
286→}
