  1→import { useEffect, useRef } from "react";
  2→import { ErrorBoundary } from "react-error-boundary";
  3→import { QueryErrorResetBoundary } from "@tanstack/react-query";
  4→import { RouterProvider } from "@tanstack/react-router";
  5→import { LazyMotion, domAnimation } from "framer-motion";
  6→import { DetachedBrowserWindow } from "@/features/browser/ui/DetachedBrowserWindow";
  7→import { ErrorFallback } from "@/shared/components";
  8→import { createBoundaryErrorHandler } from "@/shared/utils/errorReporting";
  9→import { QueryClientProvider, ThemeProvider } from "./providers";
 10→import { capabilities } from "@/platform";
 11→import { native } from "@/platform";
 12→import { DesktopShell } from "./shells/DesktopShell";
 13→import { webRouter } from "./router";
 14→
 15→// Detect if this window instance is the detached browser popup.
 16→// The main window creates it with ?window=browser-detached in the URL.
 17→const isDetachedBrowser =
 18→  new URLSearchParams(window.location.search).get("window") === "browser-detached";
 19→
 20→/**
 21→ * Safety net: ensure the window always becomes visible.
 22→ *
 23→ * The main window starts hidden (show: false in createWindow) to avoid
 24→ * a flash before onboarding/content is ready. Normally the frontend calls
 25→ * show_main_window or enter_onboarding_mode within ~1-2s. But if anything
 26→ * goes wrong (settings fetch hangs, unexpected error, hook crash), the window
 27→ * stays hidden and the user sees only a dock icon with no window.
 28→ *
 29→ * This timeout guarantees the window appears within WINDOW_SHOW_TIMEOUT_MS,
 30→ * no matter what. It's a last resort -- the normal flow or ErrorFallback
 31→ * should show the window sooner.
 32→ */
 33→const WINDOW_SHOW_TIMEOUT_MS = 5_000;
 34→
 35→function useWindowShowSafetyNet() {
 36→  const shownRef = useRef(false);
 37→  useEffect(() => {
 38→    if (shownRef.current || !capabilities.windowLifecycle) return;
 39→    const timer = setTimeout(() => {
 40→      if (!shownRef.current) {
 41→        shownRef.current = true;
 42→        console.warn("[App] Safety net: force-showing window after timeout");
 43→        native.window.show().catch(console.error);
 44→      }
 45→    }, WINDOW_SHOW_TIMEOUT_MS);
 46→    return () => clearTimeout(timer);
 47→  }, []);
 48→}
 49→
 50→function App() {
 51→  // Safety net -- force-show window if nothing else does within 5s
 52→  useWindowShowSafetyNet();
 53→
 54→  const content = isDetachedBrowser ? (
 55→    // Detached browser window: minimal shell with just the browser panel
 56→    <QueryClientProvider>
 57→      <ThemeProvider>
 58→        <DetachedBrowserWindow />
 59→      </ThemeProvider>
 60→    </QueryClientProvider>
 61→  ) : capabilities.isDesktop ? (
 62→    // Desktop (Electron): no router, direct MainLayout via DesktopShell
 63→    <QueryClientProvider>
 64→      <QueryErrorResetBoundary>
 65→        {({ reset }) => (
 66→          <ErrorBoundary
 67→            FallbackComponent={ErrorFallback}
 68→            onReset={reset}
 69→            onError={createBoundaryErrorHandler("react.error-boundary")}
 70→          >
 71→            <ThemeProvider>
 72→              <DesktopShell reset={reset} />
 73→            </ThemeProvider>
 74→          </ErrorBoundary>
 75→        )}
 76→      </QueryErrorResetBoundary>
 77→    </QueryClientProvider>
 78→  ) : (
 79→    // Web (browser): TanStack Router with full URL routing
 80→    <QueryClientProvider>
 81→      <QueryErrorResetBoundary>
 82→        {({ reset }) => (
 83→          <ErrorBoundary
 84→            FallbackComponent={ErrorFallback}
 85→            onReset={reset}
 86→            onError={createBoundaryErrorHandler("react.error-boundary")}
 87→          >
 88→            <ThemeProvider>
 89→              <RouterProvider router={webRouter} />
 90→            </ThemeProvider>
 91→          </ErrorBoundary>
 92→        )}
 93→      </QueryErrorResetBoundary>
 94→    </QueryClientProvider>
 95→  );
 96→
 97→  return (
 98→    <LazyMotion features={domAnimation} strict>
 99→      {content}
100→    </LazyMotion>
101→  );
102→}
103→
104→export default App;
