  1→// agent-server/agents/claude/message-processor.ts
  2→// Processes a single deserialized SDK message: emits canonical events, sends to
  3→// frontend, updates stream context. The agent-server is stateless — all DB
  4→// writes are handled by the backend via canonical event consumption.
  5→
  6→import { getErrorMessage } from "@shared/lib/errors";
  7→import { EventBroadcaster } from "../../event-broadcaster";
  8→import { classifyStopReason } from "../lifecycle";
  9→import type { StreamContext } from "./stream-context";
 10→import type { SessionState } from "./claude-session";
 11→
 12→// ============================================================================
 13→// Types
 14→// ============================================================================
 15→
 16→/** Options needed by processMessage that don't change per-message. */
 17→export interface ProcessMessageOptions {
 18→  sessionId: string;
 19→  generatorId: string;
 20→  model: string;
 21→  isResume: boolean;
 22→}
 23→
 24→// ============================================================================
 25→// deserializeMessage
 26→// ============================================================================
 27→
 28→/**
 29→ * Safely serializes and deserializes an SDK message to strip circular
 30→ * references and produce a clean Record<string, unknown>.
 31→ * Returns null if serialization fails (message should be skipped).
 32→ */
 33→export function deserializeMessage(
 34→  message: unknown,
 35→  generatorId: string
 36→): Record<string, unknown> | null {
 37→  try {
 38→    const seen = new WeakSet();
 39→    const messageStr = JSON.stringify(message, (_key, value) => {
 40→      if (typeof value === "object" && value !== null) {
 41→        if (seen.has(value)) return "[Circular]";
 42→        seen.add(value);
 43→      }
 44→      return value;
 45→    });
 46→    return JSON.parse(messageStr);
 47→  } catch (parseError) {
 48→    console.error(
 49→      `[${generatorId}] Failed to serialize/parse SDK message, skipping:`,
 50→      getErrorMessage(parseError)
 51→    );
 52→    return null;
 53→  }
 54→}
 55→
 56→// ============================================================================
 57→// processMessage
 58→// ============================================================================
 59→
 60→/**
 61→ * Processes a single deserialized SDK message.
 62→ *
 63→ * Side effects (in critical order):
 64→ * 1. Capture agent_session_id (one-shot, first message only, skip on resume)
 65→ * 2. Emit canonical message events (assistant, tool_result)
 66→ * 3. Send to frontend via JSON-RPC notification
 67→ * 4. Classify stop_reason and send error (AFTER sendMessage — content before error banner)
 68→ * 5. Detect result/success → set ctx.querySucceeded, emit session.idle
 69→ * 6. Detect result/error_during_execution → set ctx.lastResultError
 70→ *
 71→ * The agent-server is stateless — no DB writes. The backend persists messages
 72→ * and updates session status by consuming canonical events via the WS tunnel.
 73→ */
 74→export function processMessage(
 75→  cleanMessage: Record<string, unknown>,
 76→  ctx: StreamContext,
 77→  session: SessionState,
 78→  opts: ProcessMessageOptions
 79→): void {
 80→  // Extract common fields from the deserialized SDK message.
 81→  // cleanMessage is Record<string, unknown> (JSON.parse output), so
 82→  // we narrow once here instead of scattering `as` casts throughout.
 83→  const msg = cleanMessage.message as
 84→    | { id?: string; role?: string; content?: unknown; stop_reason?: string }
 85→    | undefined;
 86→  const parentToolUseId =
 87→    typeof cleanMessage.parent_tool_use_id === "string" ? cleanMessage.parent_tool_use_id : null;
 88→
 89→  // 1. One-shot: capture SDK session_id on the first message.
 90→  // CRITICAL: Skip capture during resume attempts. When a resume
 91→  // fails (result/error_during_execution), the SDK returns a NEW
 92→  // session_id that is useless. If we captured it, we'd overwrite
 93→  // the original working agent_session_id — permanently lost.
 94→  if (!session.agentSessionIdCaptured && cleanMessage.session_id && !opts.isResume) {
 95→    const agentSessionId = String(cleanMessage.session_id);
 96→
 97→    try {
 98→      // Emit canonical agent.session_id event — backend persists to DB.
 99→      // Set captured flag AFTER emission so a failed send allows retry on next message.
100→      EventBroadcaster.emitAgentSessionId(opts.sessionId, agentSessionId);
101→      session.agentSessionIdCaptured = true;
102→      console.log(`[${opts.generatorId}] Captured agent_session_id: ${agentSessionId}`);
103→    } catch (error) {
104→      console.error(
105→        `[${opts.generatorId}] Failed to emit agent_session_id:`,
106→        getErrorMessage(error)
107→      );
108→    }
109→  }
110→
111→  // 2. Emit canonical message events for assistant and tool_result messages
112→  if (cleanMessage.type === "assistant" && msg) {
113→    const assistantMsgId = msg.id || "unknown";
114→    EventBroadcaster.emitAssistantMessage(
115→      opts.sessionId,
116→      "claude",
117→      {
118→        id: assistantMsgId,
119→        role: "assistant",
120→        content: msg.content,
121→        stop_reason: msg.stop_reason ?? null,
122→        parent_tool_use_id: parentToolUseId,
123→      },
124→      opts.model
125→    );
126→  }
127→
128→  if (cleanMessage.type === "user" && msg) {
129→    const content = msg.content;
130→    const hasToolResult =
131→      Array.isArray(content) && content.some((b: any) => b?.type === "tool_result");
132→    if (hasToolResult) {
133→      const toolResultMsgId = msg.id || "unknown";
134→      EventBroadcaster.emitToolResultMessage(
135→        opts.sessionId,
136→        "claude",
137→        {
138→          id: toolResultMsgId,
139→          role: "user",
140→          content: msg.content,
141→          parent_tool_use_id: parentToolUseId,
142→        },
143→        opts.model
144→      );
145→    }
146→  }
147→
148→  // 3. Send to frontend via JSON-RPC notification
149→  const tSend = Date.now();
150→  EventBroadcaster.sendMessage({
151→    id: opts.sessionId,
152→    type: "message",
153→    agentType: "claude",
154→    data: cleanMessage,
155→  });
156→  const sendMs = Date.now() - tSend;
157→  if (sendMs > 5) {
158→    console.log(`[TIMING][${opts.generatorId}] sendMessage took ${sendMs}ms`);
159→  }
160→
161→  // 4. Classify stop_reason (after sendMessage — content before error banner)
162→  if (cleanMessage.type === "assistant" && msg) {
163→    const stopError = classifyStopReason(msg.stop_reason);
164→    if (stopError) {
165→      // Emit canonical session.error FIRST — backend handles DB status update.
166→      // This must succeed even if the frontend tunnel is down.
167→      EventBroadcaster.emitSessionError(
168→        opts.sessionId,
169→        "claude",
170→        stopError.message,
171→        stopError.category
172→      );
173→      // Then notify frontend (best-effort — don't let this block the canonical event)
174→      try {
175→        EventBroadcaster.sendError({
176→          id: opts.sessionId,
177→          type: "error",
178→          error: stopError.message,
179→          agentType: "claude",
180→          category: stopError.category,
181→        });
182→      } catch (error) {
183→        console.warn(
184→          `[${opts.generatorId}] Failed to send frontend error:`,
185→          getErrorMessage(error)
186→        );
187→      }
188→      ctx.stopReasonError = true;
189→    }
190→  }
191→
192→  // 5. result/success → mark query as succeeded and emit session.idle.
193→  // Must happen HERE (inside the loop), not in executeOutcome (post-loop),
194→  // because the streaming loop stays alive between turns — the prompt queue
195→  // blocks waiting for the next user message, so the post-loop never runs
196→  // until the entire conversation ends.
197→  if (cleanMessage.type === "result" && cleanMessage.subtype === "success") {
198→    ctx.querySucceeded = true;
199→
200→    // Emit canonical message.result event
201→    EventBroadcaster.emitMessageResult(opts.sessionId, "claude", "success");
202→
203→    if (!ctx.stopReasonError) {
204→      // Emit canonical session.idle — backend handles DB status update
205→      EventBroadcaster.emitSessionIdle(opts.sessionId, "claude");
206→    }
207→
208→    // Best-effort title fetch: after the first successful turn, ask the SDK
209→    // for its auto-generated session summary and emit it as a canonical event.
210→    // Fire-and-forget — title is cosmetic, don't block the stream.
211→    if (!ctx.titleFetched && session.cwd) {
212→      ctx.titleFetched = true;
213→      const sdkSessionId = cleanMessage.session_id ? String(cleanMessage.session_id) : null;
214→
215→      void (async () => {
216→        try {
217→          const { listSessions } = await import("@anthropic-ai/claude-agent-sdk");
218→          const sessions = await listSessions({ dir: session.cwd, limit: 20 });
219→          const matched = sdkSessionId ? sessions.find((s) => s.sessionId === sdkSessionId) : null;
220→          const title = matched?.summary;
221→          if (title) {
222→            EventBroadcaster.emitSessionTitle(opts.sessionId, "claude", title);
223→          }
224→        } catch (error) {
225→          console.error(
226→            `[${opts.generatorId}] Failed to fetch session title:`,
227→            getErrorMessage(error)
228→          );
229→        }
230→      })();
231→    }
232→  }
233→
234→  // 6. result/error_during_execution → capture for error diagnostics
235→  // NOTE: We intentionally do NOT clear the agent_session_id here.
236→  // Even if the resume failed, the original ID must be preserved.
237→  if (cleanMessage.type === "result" && cleanMessage.subtype === "error_during_execution") {
238→    const errors = cleanMessage.errors as string[] | undefined;
239→    const resultError =
240→      Array.isArray(errors) && errors.length > 0
241→        ? errors.join("; ")
242→        : typeof cleanMessage.error === "string"
243→          ? cleanMessage.error
244→          : "unknown";
245→    ctx.lastResultError = resultError;
246→    console.error(`[${opts.generatorId}] result/error_during_execution: ${resultError}`);
247→  }
248→}
249→

  1→// backend/src/services/agent/persistence.ts
  2→// Database write functions for persisting canonical agent events.
  3→//
  4→// Adapted from agent-server/db/session-writer.ts. Key differences:
  5→// - Uses backend's getDatabase() (not agent-server's)
  6→// - No notifyBackend() calls (backend handles WS push via invalidate())
  7→// - No FrontendClient calls (backend pushes via query-engine directly)
  8→// - Takes event objects instead of positional args
  9→//
 10→// All functions are synchronous (better-sqlite3 is synchronous).
 11→// Callers (event-handler.ts) call invalidate() after persistence succeeds.
 12→
 13→import { getDatabase } from "../../lib/database";
 14→import { uuidv7 } from "@shared/lib/uuid";
 15→import { getErrorMessage } from "@shared/lib/errors";
 16→import type {
 17→  MessageAssistantEvent,
 18→  MessageToolResultEvent,
 19→  MessageResultEvent,
 20→  MessageCancelledEvent,
 21→  SessionStartedEvent,
 22→  SessionIdleEvent,
 23→  SessionErrorEvent,
 24→  SessionCancelledEvent,
 25→  AgentSessionIdEvent,
 26→  SessionTitleEvent,
 27→} from "@shared/agent-events";
 28→
 29→// ============================================================================
 30→// WriteResult type (mirrors agent-server's pattern)
 31→// ============================================================================
 32→
 33→export type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 34→
 35→// ============================================================================
 36→// Message writes
 37→// ============================================================================
 38→
 39→/**
 40→ * Save an assistant message to the messages table.
 41→ * Mirrors agent-server saveAssistantMessage() logic:
 42→ * - Generates a local UUID7 message ID
 43→ * - Stores flat content array, except for cancelled messages which get an envelope
 44→ * - Records the agent_message_id and parent_tool_use_id for linking
 45→ */
 46→export function persistAssistantMessage(event: MessageAssistantEvent): WriteResult {
 47→  const db = getDatabase();
 48→  const messageId = uuidv7();
 49→  const sentAt = new Date().toISOString();
 50→
 51→  // Store flat content array for normal messages. For "cancelled" messages,
 52→  // write envelope so the frontend can detect cancellation from DB content.
 53→  const contentPayload =
 54→    event.message.stop_reason === "cancelled"
 55→      ? { message: { stop_reason: "cancelled" }, blocks: event.message.content ?? [] }
 56→      : (event.message.content ?? []);
 57→  const content = JSON.stringify(contentPayload);
 58→
 59→  try {
 60→    db.prepare(
 61→      `INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 62→       VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)`
 63→    ).run(
 64→      messageId,
 65→      event.sessionId,
 66→      content,
 67→      sentAt,
 68→      event.model || null,
 69→      event.message.id || null,
 70→      event.message.parent_tool_use_id || null
 71→    );
 72→    return { ok: true, value: messageId };
 73→  } catch (error) {
 74→    const msg = getErrorMessage(error);
 75→    console.error(`[AgentPersistence] Failed to save assistant message:`, msg);
 76→    return { ok: false, error: msg };
 77→  }
 78→}
 79→
 80→/**
 81→ * Save a tool_result message (role='user') to the messages table.
 82→ * These contain tool execution results that link tool_use blocks to their outputs.
 83→ */
 84→export function persistToolResultMessage(event: MessageToolResultEvent): WriteResult {
 85→  const db = getDatabase();
 86→  const messageId = uuidv7();
 87→  const sentAt = new Date().toISOString();
 88→  const content = JSON.stringify(event.message.content ?? []);
 89→
 90→  try {
 91→    db.prepare(
 92→      `INSERT INTO messages (id, session_id, role, content, sent_at, agent_message_id, parent_tool_use_id)
 93→       VALUES (?, ?, 'user', ?, ?, ?, ?)`
 94→    ).run(
 95→      messageId,
 96→      event.sessionId,
 97→      content,
 98→      sentAt,
 99→      event.message.id || null,
100→      event.message.parent_tool_use_id || null
101→    );
102→    return { ok: true, value: messageId };
103→  } catch (error) {
104→    const msg = getErrorMessage(error);
105→    console.error(`[AgentPersistence] Failed to save tool_result message:`, msg);
106→    return { ok: false, error: msg };
107→  }
108→}
109→
110→/**
111→ * Handle message.result events. No DB write needed — this is informational
112→ * (success/error_during_execution subtypes). Session status transitions are
113→ * handled by separate session.idle / session.error events.
114→ */
115→export function persistMessageResult(_event: MessageResultEvent): void {
116→  // No-op: message.result is informational only.
117→  // Session status is managed by session.idle / session.error events.
118→}
119→
120→/**
121→ * Persist a cancellation: insert a cancelled assistant message marker
122→ * and set session status to idle.
123→ *
124→ * The cancelled message uses the envelope format so the frontend can detect
125→ * cancellation on reload (the "Turn interrupted" label in AssistantTurn).
126→ */
127→export function persistMessageCancelled(event: MessageCancelledEvent): WriteResult {
128→  const db = getDatabase();
129→  const messageId = uuidv7();
130→  const sentAt = new Date().toISOString();
131→
132→  // Empty cancelled message with envelope so frontend detects cancellation
133→  const content = JSON.stringify({
134→    message: { stop_reason: "cancelled" },
135→    blocks: [],
136→  });
137→
138→  try {
139→    db.transaction(() => {
140→      db.prepare(
141→        `INSERT INTO messages (id, session_id, role, content, sent_at, cancelled_at)
142→         VALUES (?, ?, 'assistant', ?, ?, ?)`
143→      ).run(messageId, event.sessionId, content, sentAt, sentAt);
144→
145→      db.prepare(
146→        `UPDATE sessions SET status = 'idle', error_message = NULL, error_category = NULL, updated_at = datetime('now') WHERE id = ?`
147→      ).run(event.sessionId);
148→    })();
149→
150→    return { ok: true, value: messageId };
151→  } catch (error) {
152→    const msg = getErrorMessage(error);
153→    console.error(`[AgentPersistence] Failed to persist message.cancelled:`, msg);
154→    return { ok: false, error: msg };
155→  }
156→}
