299→/** Update session title and auto-set workspace title if not already set. */
300→export function persistSessionTitle(event: SessionTitleEvent): WriteResult<void> {
301→  const db = getDatabase();
302→
303→  try {
304→    db.transaction(() => {
305→      // Always update session title
306→      db.prepare(`UPDATE sessions SET title = ?, updated_at = datetime('now') WHERE id = ?`).run(
307→        event.title,
308→        event.sessionId
309→      );
310→
311→      // Auto-set workspace title only if not already set (preserves PR titles and user renames)
312→      db.prepare(
313→        `UPDATE workspaces SET title = ?
314→         WHERE id = (SELECT workspace_id FROM sessions WHERE id = ?)
315→         AND title IS NULL`
316→      ).run(event.title, event.sessionId);
317→    })();
318→    return { ok: true, value: undefined };
319→  } catch (error) {
320→    const msg = getErrorMessage(error);
321→    console.error(`[AgentPersistence] Failed to persist session.title:`, msg);
322→    return { ok: false, error: msg };
323→  }
324→}
