  1→/**
  2→ * DesktopShell -- Electron desktop mode, no routing.
  3→ *
  4→ * Contains ALL of the existing AppContent gate logic (auth, settings,
  5→ * onboarding, backend error). Renders MainLayout directly without a router.
  6→ *
  7→ * This is the Electron-only code path. Web mode uses TanStack Router instead.
  8→ */
  9→
 10→import { useEffect, useRef } from "react";
 11→import { ErrorBoundary } from "react-error-boundary";
 12→import { MainLayout } from "../layouts/MainLayout";
 13→import { DashboardError } from "@/shared/components";
 14→import { createBoundaryErrorHandler } from "@/shared/utils/errorReporting";
 15→import { Toaster } from "@/components/ui/sonner";
 16→import { OnboardingOverlay } from "@/features/onboarding";
 17→import { useSettings } from "@/features/settings";
 18→import { useAuth, PairGatePage } from "@/features/auth";
 19→import { native } from "@/platform";
 20→import { ServerOfflinePage } from "@/features/connection";
 21→import { initNotifications } from "@/platform/notifications";
 22→import { useGlobalSessionNotifications } from "@/features/session/hooks/useGlobalSessionNotifications";
 23→import { useWorkspaceInitEvents } from "@/features/workspace/hooks/useWorkspaceInitEvents";
 24→import { useQueryProtocol } from "@/shared/hooks/useQueryProtocol";
 25→import { useBackendRestart } from "@/shared/hooks/useBackendRestart";
 26→import { useAutoUpdate, useUpdateToast, UpdateProvider } from "@/features/updates";
 27→import { useAnalyticsConsent } from "@/platform/analytics";
 28→export function DesktopShell({ reset }: { reset: () => void }) {
 29→  const auth = useAuth();
 30→  const settingsQuery = useSettings();
 31→  const windowShownRef = useRef(false);
 32→
 33→  // Request OS notification permission once on mount
 34→  useEffect(() => {
 35→    initNotifications();
 36→  }, []);
 37→
 38→  // Global listener: fire OS notifications for ALL session events when backgrounded
 39→  useGlobalSessionNotifications();
 40→
 41→  // Global listener: workspace init progress -> invalidate queries on completion
 42→  useWorkspaceInitEvents();
 43→
 44→  // Global listener: WS query protocol -> direct cache updates + invalidation dispatch
 45→  useQueryProtocol();
 46→
 47→  // Global listener: backend restart -> update cached port + force WS reconnect
 48→  useBackendRestart();
 49→
 50→  // Sync PostHog opt-in/out state with analytics_enabled setting
 51→  useAnalyticsConsent();
 52→
 53→  // Auto-update: check on launch + every 5 min, show toast when ready
 54→  const autoUpdate = useAutoUpdate();
 55→  useUpdateToast(autoUpdate);
 56→
 57→  const showOnboarding = !settingsQuery.isError && !settingsQuery.data?.onboarding_completed;
 58→
 59→  // Boot diagnostics -- trace the window-show flow so we can see what's blocking
 60→  useEffect(() => {
 61→    if (import.meta.env.DEV) {
 62→      console.log("[DesktopShell] mount -- auth:", {
 63→        isLoading: auth.isLoading,
 64→        isAuthenticated: auth.isAuthenticated,
 65→      });
 66→      console.log("[DesktopShell] mount -- settings:", {
 67→        isLoading: settingsQuery.isLoading,
 68→        isError: settingsQuery.isError,
 69→        hasData: !!settingsQuery.data,
 70→        onboardingCompleted: settingsQuery.data?.onboarding_completed,
 71→        showOnboarding,
 72→      });
 73→    }
 74→  }, [
 75→    auth.isLoading,
 76→    auth.isAuthenticated,
 77→    settingsQuery.isLoading,
 78→    settingsQuery.isError,
 79→    settingsQuery.data,
 80→    showOnboarding,
 81→  ]);
 82→
 83→  // Show the main window whenever we transition OUT of onboarding.
 84→  useEffect(() => {
 85→    if (settingsQuery.isLoading) return;
 86→    if (showOnboarding) {
 87→      windowShownRef.current = false;
 88→      return;
 89→    }
 90→    if (windowShownRef.current) return;
 91→    native.window.show().catch(console.error);
 92→    windowShownRef.current = true;
 93→  }, [settingsQuery.isLoading, showOnboarding]);
 94→
 95→  // Remote browser auth gate: show pairing page if not authenticated
 96→  if (auth.isLoading) return null;
 97→  if (!auth.isAuthenticated) return <PairGatePage onPaired={auth.onPaired} />;
 98→
 99→  // While settings load, render nothing -- window is hidden anyway
100→  if (settingsQuery.isLoading) return null;
101→
102→  // Backend unreachable -- show error instead of white screen
103→  if (settingsQuery.isError && !settingsQuery.data) {
104→    return <ServerOfflinePage onRetry={() => settingsQuery.refetch()} variant="desktop" />;
105→  }
106→
107→  if (showOnboarding) {
108→    return <OnboardingOverlay />;
109→  }
110→
111→  return (
112→    <UpdateProvider value={autoUpdate}>
113→      <ErrorBoundary
114→        FallbackComponent={DashboardError}
115→        onReset={reset}
116→        onError={createBoundaryErrorHandler("react.error-boundary.root")}
117→      >
118→        <MainLayout />
119→      </ErrorBoundary>
120→      <Toaster />
121→    </UpdateProvider>
122→  );
123→}
