 65→/**
 66→ * Emit workspace init progress via stdout JSON protocol.
 67→ * Electron's backend-process.ts reads stdout line-by-line and relays lines
 68→ * prefixed with DEUS_WORKSPACE_PROGRESS: as IPC events.
 69→ */
 70→export function emitProgress(workspaceId: string, step: string, label: string): void {
 71→  const payload = JSON.stringify({ workspaceId, step, label });
 72→  process.stdout.write(`DEUS_WORKSPACE_PROGRESS:${payload}\n`);
 73→}
