 53→/**
 54→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 55→ * Must be rendered inside SidebarProvider to access sidebar open state.
 56→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 57→ */
 58→function SidebarResizeHandle({
 59→  onSizeChange,
 60→  onDraggingChange,
 61→}: {
 62→  onSizeChange: (size: number | null) => void;
 63→  onDraggingChange: (dragging: boolean) => void;
 64→}) {
 65→  const { open } = useSidebar();
 66→
 67→  const { handleProps, isDragging } = useResizeHandle({
 68→    onSizeChange,
 69→    enabled: open,
 70→    direction: "horizontal",
 71→    mode: "primary",
 72→    minPrimarySize: 200,
 73→    minSecondarySize: 400,
 74→  });
 75→
 76→  // Notify parent of drag state changes to disable sidebar transitions
 77→  useEffect(() => {
 78→    onDraggingChange(isDragging);
 79→  }, [isDragging, onDraggingChange]);
 80→
 81→  if (!open) return null;
 82→
 83→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 84→}
