 85→  // Effective tab: if the stored tab is hidden by experimental settings, fall back to "changes".
 86→  const experimentalSettings = useSettings().data;
 87→  const effectiveContentTab = isTabVisible(contentTab, experimentalSettings)
 88→    ? contentTab
 89→    : "changes";
 90→
 91→  const isBrowserDetached = useBrowserWindowStore((s) => s.detachedWindowOpen);
 92→  const connectionState = useConnectionState().state;
 93→  const isDisconnected = connectionState === "disconnected";
 94→
 95→  // --- Workspace actions (PR bridge, archive, retry, manifest) ---
