116→  const statusMutation = useUpdateWorkspaceStatus();
117→
118→  // Only start watching and querying diffs once the worktree checkout is complete.
119→  const isReady = selectedWorkspace?.state === "ready";
120→
121→  // Watch workspace for file changes (event-driven cache invalidation)
122→  const isWatched = useFileWatcher(
123→    isReady ? (selectedWorkspace?.workspace_path ?? null) : null,
124→    isReady ? selectedWorkspaceId : null
