126→
127→  // --- Refs for imperative panel control ---
128→  const chatPanelRef = useRef<ImperativePanelHandle>(null);
129→  const contentPanelRef = useRef<ImperativePanelHandle>(null);
130→  const panelGroupContainerRef = useRef<HTMLDivElement>(null);
131→
132→  // Dynamic collapsed size: 36px strip -> percentage of container width.
133→  const MIN_PANEL_SIZE = 15;
