265→        {/* Sidebar toggle -- visible when sidebar collapsed (desktop) or always on mobile welcome */}
266→        {(!sidebarOpen || isMobile) && !selectedWorkspace && (
267→          <button
268→            type="button"
269→            data-slot="welcome-sidebar-toggle"
270→            aria-label="Expand sidebar"
271→            onClick={toggleSidebar}
272→            className="text-muted-foreground/60 hover:text-foreground hover:bg-foreground/5 absolute top-3 left-3 z-10 flex h-7 w-7 items-center justify-center rounded-lg transition-[transform,color,background-color] duration-200 ease-out"
273→          >
274→            <PanelLeft className="h-4 w-4" />
275→          </button>
276→        )}
277→
278→        {selectedWorkspace ? (
279→          isMobile ? (
280→            /* Mobile: single-panel layout with bottom tab bar */
281→            <MobileLayout
282→              key={selectedWorkspace.id}
283→              workspace={selectedWorkspace}
284→              workspaceChatPanelRef={workspaceChatPanelRef}
285→              sendAgentMessageHandler={sendAgentMessageHandler}
286→              handleSendAgentMessage={handleSendAgentMessage}
287→              onRetrySetup={
288→                selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
289→              }
290→              onViewSetupLogs={
291→                selectedWorkspace.setup_status === "failed" ? handleViewSetupLogs : undefined
292→              }
293→              setCreatePRHandler={setCreatePRHandler}
294→              setSendAgentMessageHandler={setSendAgentMessageHandler}
295→              isWatched={isWatched}
296→              manifestTasks={manifestTasks}
297→              hasManifest={hasManifest}
298→              onRunTask={handleRunTask}
