359→export function useCreateWorkspace() {
360→  const queryClient = useQueryClient();
361→  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
362→
363→  return useMutation({
364→    mutationFn: (params: CreateWorkspaceParams) => {
365→      const repoId = typeof params === "string" ? params : params.repositoryId;
366→      const options =
367→        typeof params === "string"
368→          ? undefined
369→          : {
370→              source_branch: params.source_branch,
371→              pr_number: params.pr_number,
372→              pr_url: params.pr_url,
373→              pr_title: params.pr_title,
374→              target_branch: params.target_branch,
375→            };
376→      return WorkspaceService.create(repoId, options);
377→    },
378→
379→    onMutate: async (params: CreateWorkspaceParams) => {
380→      const repositoryId = typeof params === "string" ? params : params.repositoryId;
381→      await queryClient.cancelQueries({ queryKey });
382→
383→      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
384→
385→      // Inject a placeholder workspace into the matching repo group
386→      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
387→        if (!old) return old;
388→        return produce(old, (draft) => {
389→          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
390→          if (repoGroup) {
391→            repoGroup.workspaces.unshift(
392→              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
393→            );
394→          }
395→        });
396→      });
397→
398→      return { previousData };
399→    },
400→
401→    onError: (_err, _params, context) => {
402→      if (context?.previousData) {
403→        queryClient.setQueryData(queryKey, context.previousData);
404→      }
405→    },
406→
407→    onSuccess: (_data, params) => {
408→      const repositoryId = typeof params === "string" ? params : params.repositoryId;
409→      track("workspace_created", { repository_id: repositoryId });
410→    },
411→
412→    onSettled: () => {
413→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
414→    },
415→  });
416→}
