593→    mutationFn: ({ workspaceId, systemPrompt }: { workspaceId: string; systemPrompt: string }) =>
594→      WorkspaceService.updateSystemPrompt(workspaceId, systemPrompt),
595→
596→    // Optimistic update: Show new prompt immediately
597→    onMutate: async ({ workspaceId, systemPrompt }) => {
598→      await queryClient.cancelQueries({
599→        queryKey: queryKeys.workspaces.systemPrompt(workspaceId),
600→      });
601→
602→      const previousPrompt = queryClient.getQueryData<string>(
603→        queryKeys.workspaces.systemPrompt(workspaceId)
604→      );
605→
606→      queryClient.setQueryData(queryKeys.workspaces.systemPrompt(workspaceId), systemPrompt);
607→
608→      return { previousPrompt };
609→    },
610→
611→    onError: (_err, variables, context) => {
612→      if (context?.previousPrompt !== undefined) {
613→        queryClient.setQueryData(
614→          queryKeys.workspaces.systemPrompt(variables.workspaceId),
615→          context.previousPrompt
616→        );
617→      }
618→    },
619→
620→    onSettled: (_, __, variables) => {
621→      queryClient.invalidateQueries({
622→        queryKey: queryKeys.workspaces.systemPrompt(variables.workspaceId),
623→      });
624→    },
625→  });
626→}
